"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { Activity, ArrowRight, Shield, Stethoscope } from "lucide-react";

export default function Footer() {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const id = window.requestAnimationFrame(() => setIsVisible(true));
    return () => window.cancelAnimationFrame(id);
  }, []);

  return (
    <footer
      className={
        "relative mt-16 overflow-hidden border-t border-white/10 bg-slate-900 text-white" +
        " transition-all duration-700 ease-out" +
        (isVisible ? " opacity-100 translate-y-0" : " opacity-0 translate-y-2")
      }
    >
      <div className="pointer-events-none absolute inset-0 bg-linear-to-tr from-indigo-500/10 via-transparent to-sky-500/10 blur-2xl" />

      <div className="relative mx-auto max-w-7xl px-6 py-16">
        {/* Top CTA */}
        <div className="mb-14 rounded-2xl border border-white/10 bg-white/5 backdrop-blur-xl">
          <div className="flex flex-col gap-8 p-8 md:flex-row md:items-center md:justify-between md:p-10">
            <div>
              <p className="inline-flex items-center gap-2 rounded-full border border-indigo-500/20 bg-indigo-500/10 px-3 py-1 text-xs text-indigo-300">
                <Activity className="h-3.5 w-3.5" />
                HealthChain
              </p>
              <h2 className="mt-4 text-2xl font-semibold md:text-3xl">
                Secure records. Clear access. Real trust.
              </h2>
              <p className="mt-2 max-w-2xl text-sm text-gray-400">
                Manage healthcare data with role-based access and blockchain-backed integrity.
              </p>
            </div>

            <div className="flex flex-wrap items-center gap-3">
              <Link href="/auth/register" className="inline-flex">
                <span className="inline-flex items-center gap-2 rounded-xl bg-white px-6 py-3 text-sm font-medium text-black transition-transform hover:scale-[1.03]">
                  Get Started
                  <ArrowRight size={16} />
                </span>
              </Link>
              <Link
                href="/auth/login"
                className="inline-flex rounded-xl border border-white/10 px-6 py-3 text-sm font-medium text-gray-200 transition-colors hover:bg-white/10"
              >
                Login
              </Link>
            </div>
          </div>
        </div>

        {/* Main footer */}
        <div className="grid gap-10 md:grid-cols-3">
          <div>
            <div className="flex items-center gap-2">
              <div className="rounded-lg bg-indigo-500/20 p-2">
                <Activity className="h-5 w-5 text-indigo-300" />
              </div>
              <h3 className="text-lg font-semibold tracking-tight">HealthChain</h3>
            </div>
            <p className="mt-3 text-sm text-gray-400">
              A decentralized healthcare record system designed for privacy, integrity, and accountability.
            </p>

            <div className="mt-6 grid grid-cols-3 gap-3 text-xs text-gray-300">
              <div className="rounded-xl border border-white/10 bg-white/5 p-3">
                <div className="flex items-center gap-2">
                  <Shield className="h-4 w-4 text-indigo-300" />
                  Secure
                </div>
                <p className="mt-2 text-[11px] text-gray-400">Immutable audit trail</p>
              </div>
              <div className="rounded-xl border border-white/10 bg-white/5 p-3">
                <div className="flex items-center gap-2">
                  <Stethoscope className="h-4 w-4 text-sky-300" />
                  Clinical
                </div>
                <p className="mt-2 text-[11px] text-gray-400">Doctor workflows</p>
              </div>
              <div className="rounded-xl border border-white/10 bg-white/5 p-3">
                <div className="flex items-center gap-2">
                  <Activity className="h-4 w-4 text-emerald-300" />
                  Access
                </div>
                <p className="mt-2 text-[11px] text-gray-400">Role-based sharing</p>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-8">
            <div>
              <h4 className="text-sm font-semibold">Quick Links</h4>
              <div className="mt-4 flex flex-col gap-3 text-sm text-gray-400">
                <Link href="/" className="transition-colors hover:text-white">
                  Home
                </Link>
                <Link href="/auth/login" className="transition-colors hover:text-white">
                  Login
                </Link>
                <Link href="/auth/register" className="transition-colors hover:text-white">
                  Register
                </Link>
              </div>
            </div>

            <div>
              <h4 className="text-sm font-semibold">Roles</h4>
              <div className="mt-4 flex flex-col gap-3 text-sm text-gray-400">
                <Link href="/dashboard/patient" className="transition-colors hover:text-white">
                  Patient
                </Link>
                <Link href="/dashboard/doctor" className="transition-colors hover:text-white">
                  Doctor
                </Link>
                <Link href="/dashboard/government" className="transition-colors hover:text-white">
                  Government
                </Link>
              </div>
            </div>
          </div>

          <div className="rounded-2xl border border-white/10 bg-white/5 p-6 backdrop-blur-xl">
            <h4 className="text-sm font-semibold">On-chain footprint</h4>
            <p className="mt-3 text-sm text-gray-400">
              Only references (like an IPFS hash) are stored on-chain. Medical reports remain off-chain.
            </p>
            <p className="mt-4 text-xs text-gray-500">
              © {new Date().getFullYear()} HealthChain. All rights reserved.
            </p>
          </div>
        </div>
      </div>
    </footer>
  );
}
